INSERT INTO reading_notes (id, user_id, book_id, note_text, page_number, percent_complete, mood, pace, created_at) VALUES ('779fe4e6-2c5b-4eb2-86ec-27b3d73fb0ee', 'c2f3eb27-139f-4605-9566-8ded8d9e1336', '6a5c90d7-e607-427b-afef-8e8c0471cb6c', 'I absolutely did NOT remember that Vis heard the Sextus visiting the Sappers talking about things that would come up later about the climactic events near the end of the book.', NULL, 3, 'curious', 'steady', '2026-03-19 02:14:30');
